import { TechSnippetData } from "./technologySnippets";

// Minimal but complete snippet data for remaining technologies
const createTechData = (name: string, lang: string, snippets: {t:string,l:string,c:string}[]): TechSnippetData => ({
  snippets: [
    { title: snippets[0]?.t||"security."+lang.toLowerCase(), language: lang, badge: "🔒 Secure Code", badgeColor: "#0059B3", description: `Enterprise-grade security implementation. At WebQ, we enforce security best practices across all ${name} deployments.`, lines: snippets[0]?.c.split("\n")||[] },
    { title: snippets[1]?.t||"performance."+lang.toLowerCase(), language: lang, badge: "⚡ Performance", badgeColor: "#0070C0", description: `Optimized ${name} configuration for peak performance. At WebQ, we tune every deployment for maximum throughput.`, lines: snippets[1]?.c.split("\n")||[] },
    { title: snippets[2]?.t||"test."+lang.toLowerCase(), language: lang, badge: "🧪 Testing", badgeColor: "#0080CC", description: `Comprehensive testing strategy for ${name}. At WebQ, we validate all configurations before production deployment.`, lines: snippets[2]?.c.split("\n")||[] },
    { title: snippets[3]?.t||"logging."+lang.toLowerCase(), language: lang, badge: "📝 Logging", badgeColor: "#0090D6", description: `Structured logging and monitoring for ${name}. At WebQ, we centralize all logs for unified observability.`, lines: snippets[3]?.c.split("\n")||[] },
    { title: snippets[4]?.t||"errors."+lang.toLowerCase(), language: lang, badge: "🛡️ Exception Handling", badgeColor: "#007AB8", description: `Robust error handling for ${name}. At WebQ, we implement graceful degradation and automated recovery.`, lines: snippets[4]?.c.split("\n")||[] },
    { title: snippets[5]?.t||"ux."+lang.toLowerCase(), language: lang, badge: "👤 User-Friendly", badgeColor: "#0099CC", description: `User-friendly ${name} configuration. At WebQ, we design intuitive interfaces and clear feedback loops.`, lines: snippets[5]?.c.split("\n")||[] },
    { title: snippets[6]?.t||"best-practice."+lang.toLowerCase(), language: lang, badge: "📐 Best Practice", badgeColor: "#1A6BAF", description: `${name} best practices and patterns. At WebQ, we follow industry standards for maintainable, scalable solutions.`, lines: snippets[6]?.c.split("\n")||[] },
    { title: snippets[7]?.t||"events."+lang.toLowerCase(), language: lang, badge: "🔄 Event-Driven", badgeColor: "#0085C2", description: `Event-driven architecture with ${name}. At WebQ, we build reactive, loosely-coupled systems.`, lines: snippets[7]?.c.split("\n")||[] },
    { title: snippets[8]?.t||"docs.md", language: "Markdown", badge: "📖 Documentation", badgeColor: "#3378B5", description: `Comprehensive ${name} documentation. At WebQ, we maintain detailed runbooks for every deployment.`, lines: snippets[8]?.c.split("\n")||[] },
  ],
  metrics: [],
  industries: [],
  webqCallout: `At WebQ, we deliver enterprise-grade ${name} solutions with security, performance, and reliability built in from day one.`,
});

