export const sparkMllib: TechSnippetData = { snippets: [ { title: "security.py", language: "Python", badge: "🔒 Secure Code", badgeColor: "#89b4fa", description: "Spark security with Kerberos and encryption. At WebQ, we secure all Spark clusters with authentication and data encryption.", lines: s("from pyspark.sql import SparkSession\n\nspark = SparkSession.builder \\\n    .appName('SecureML') \\\n    .config('spark.authenticate', 'true') \\\n    .config('spark.network.crypto.enabled', 'true') \\\n    .config('spark.io.encryption.enabled', 'true') \\\n    .config('spark.sql.sources.partitionOverwriteMode', 'dynamic') \\\n    .getOrCreate()\n\n# Column-level encryption\nfrom pyspark.sql.functions import sha2\ndf = df.withColumn('email_hash', sha2('email', 256))") }, { title: "ml_pipeline.py", language: "Python", badge: "⚡ Performance", badgeColor: "#89b4fa", description: "Distributed ML pipeline with caching. At WebQ, we optimize Spark MLlib jobs with partitioning and broadcast joins.", lines: s("from pyspark.ml import Pipeline\nfrom pyspark.ml.feature import VectorAssembler, StandardScaler\nfrom pyspark.ml.classification import RandomForestClassifier\n\nassembler = VectorAssembler(\n    inputCols=['feature1', 'feature2', 'feature3'],\n    outputCol='features'\n)\nscaler = StandardScaler(inputCol='features', outputCol='scaled')\nrf = RandomForestClassifier(featuresCol='scaled', numTrees=100)\n\npipeline = Pipeline(stages=[assembler, scaler, rf])\n\n# Cache training data for iterative training\ntrain_df.cache()\nmodel = pipeline.fit(train_df)") }, { title: "test_pipeline.py", language: "Python", badge: "🧪 Testing", badgeColor: "#89b4fa", description: "Spark ML testing with evaluation metrics. At WebQ, we validate distributed models with cross-validation.", lines: s("from pyspark.ml.evaluation import MulticlassClassificationEvaluator\nfrom pyspark.ml.tuning import CrossValidator, ParamGridBuilder\n\nevaluator = MulticlassClassificationEvaluator(\n    labelCol='label', metricName='f1'\n)\n\nparamGrid = ParamGridBuilder() \\\n    .addGrid(rf.numTrees, [50, 100, 200]) \\\n    .addGrid(rf.maxDepth, [5, 10]) \\\n    .build()\n\ncv = CrossValidator(\n    estimator=pipeline, estimatorParamMaps=paramGrid,\n    evaluator=evaluator, numFolds=3\n)\ncvModel = cv.fit(train_df)\nprint(f'Best F1: {evaluator.evaluate(cvModel.transform(test_df)):.3f}')") }, { title: "logging.py", language: "Python", badge: "📝 Logging", badgeColor: "#89b4fa", description: "MLflow with Spark tracking. At WebQ, we track distributed training runs with model lineage.", lines: s("import mlflow\nimport mlflow.spark\n\nwith mlflow.start_run():\n    model = pipeline.fit(train_df)\n    predictions = model.transform(test_df)\n    f1 = evaluator.evaluate(predictions)\n\n    mlflow.log_param('numTrees', 100)\n    mlflow.log_metric('f1', f1)\n    mlflow.spark.log_model(model, 'spark-model')") }, { title: "error_handler.py", language: "Python", badge: "🛡️ Exception Handling", badgeColor: "#89b4fa", description: "Spark job error handling with checkpointing. At WebQ, we implement fault-tolerant ML pipelines with recovery.", lines: s("from pyspark.sql.utils import AnalysisException\n\ndef safe_ml_job(spark, input_path):\n    try:\n        df = spark.read.parquet(input_path)\n        df.cache()\n        if df.count() == 0:\n            raise ValueError('Empty dataset')\n        model = pipeline.fit(df)\n        model.write().overwrite().save('models/latest')\n    except AnalysisException as e:\n        logger.error(f'Schema error: {e}')\n    except Exception as e:\n        logger.error(f'ML job failed: {e}')\n        raise") }, { title: "feature_store.py", language: "Python", badge: "👤 User-Friendly", badgeColor: "#89b4fa", description: "Feature engineering at scale. At WebQ, we build reusable feature pipelines for consistent ML training.", lines: s("from pyspark.ml.feature import Bucketizer, StringIndexer\n\n# Time-based features\ndf = df.withColumn('hour', hour('timestamp'))\ndf = df.withColumn('day_of_week', dayofweek('timestamp'))\n\n# Bucketing continuous features\nbucketizer = Bucketizer(\n    splits=[0, 18, 25, 35, 50, 65, 100],\n    inputCol='age', outputCol='age_group'\n)\n\n# Encoding categoricals\nindexer = StringIndexer(\n    inputCol='category', outputCol='category_idx'\n)\n\ndf = bucketizer.transform(df)\ndf = indexer.fit(df).transform(df)") }, { title: "model_serving.py", language: "Python", badge: "📐 Best Practice", badgeColor: "#89b4fa", description: "Model export for serving. At WebQ, we export Spark ML models to PMML/MLeap for low-latency serving.", lines: s("# Save model\nmodel.write().overwrite().save('s3://models/rf-v2')\n\n# Load for batch scoring\nfrom pyspark.ml import PipelineModel\nloaded = PipelineModel.load('s3://models/rf-v2')\npredictions = loaded.transform(new_data)\n\n# Export to MLeap for real-time serving\nimport mleap.pyspark\nmodel.serializeToBundle(\n    'jar:file:/models/rf-v2.zip',\n    loaded.transform(train_df)\n)") }, { title: "streaming_ml.py", language: "Python", badge: "🔄 Event-Driven", badgeColor: "#89b4fa", description: "Streaming ML with Structured Streaming. At WebQ, we score real-time events with pre-trained Spark models.", lines: s("stream_df = spark.readStream \\\n    .format('kafka') \\\n    .option('kafka.bootstrap.servers', 'kafka:9092') \\\n    .option('subscribe', 'events') \\\n    .load()\n\n# Apply ML model to stream\nscored = model.transform(stream_df)\n\nquery = scored.writeStream \\\n    .outputMode('append') \\\n    .format('parquet') \\\n    .option('path', 's3://results/predictions') \\\n    .option('checkpointLocation', 's3://checkpoints/ml') \\\n    .start()") }, { title: "README.md", language: "Markdown", badge: "📖 Documentation", badgeColor: "#89b4fa", description: "Spark ML pipeline documentation. At WebQ, we document distributed ML workflows with data lineage.", lines: s("# Customer Scoring Pipeline\n\n## Architecture\nKafka → Spark Streaming → ML Model → Parquet → Dashboard\n\n## Model\n- Algorithm: Random Forest (100 trees)\n- Features: 25 engineered features\n- Training: 10M records, weekly retrain\n\n## Performance\n- F1: 0.91 | AUC: 0.95\n- Batch scoring: 1M records/min\n- Streaming latency: <500ms\n\n## Deployment\n```bash\nspark-submit --master yarn ml_pipeline.py\n```") } ], metrics: [ { value: "39K+", label: "GitHub Stars", detail: "Apache Spark" }, { value: "#1", label: "Distributed ML", detail: "Big data standard" }, { value: "PB-Scale", label: "Data Processing", detail: "Petabyte workloads" }, { value: "100x", label: "Faster than MapReduce", detail: "In-memory computing" }, { value: "Databricks", label: "Commercial Platform", detail: "Enterprise support" }, { value: "Python/Java/Scala", label: "Multi-Language", detail: "API support" }, { value: "10K+", label: "Companies", detail: "Production usage" }, { value: "Streaming", label: "Real-time ML", detail: "Structured Streaming" } ], industries: [ { industry: "Finance", adoption: 80, use: "Risk modeling, fraud detection" }, { industry: "Telecommunications", adoption: 75, use: "Network analytics, churn" }, { industry: "Retail", adoption: 70, use: "Recommendation engines" }, { industry: "Healthcare", adoption: 55, use: "Genomics, population health" }, { industry: "Ad Tech", adoption: 78, use: "Real-time bidding, targeting" }, { industry: "Manufacturing", adoption: 50, use: "Predictive maintenance" } ], webqCallout: "At WebQ, we build Spark MLlib pipelines for enterprise-scale ML — with distributed training, streaming inference, and fault-tolerant batch processing." };

